sql:
SELECT campaign_name, status
FROM ad_campaigns
WHERE campaign_id IN (
    SELECT campaign_id
    FROM campaign_sales
);

SELECT campaign_name, budget, sales
FROM ad_campaigns
WHERE campaign_id = 1;

SELECT SUM(budget) AS total_budget
FROM ad_campaigns
WHERE season_id = (SELECT season_id FROM seasons WHERE season_name = 'Summer');

SELECT COUNT(*)
FROM ad_campaigns
WHERE campaign_id IN (SELECT campaign_id FROM campaign_sales);

SELECT SUM(sales_amount) AS total_sales
FROM campaign_sales
WHERE campaign_id = 1;

SELECT campaign_name
FROM ad_campaigns
WHERE campaign_id = 1;
